SELECT r.id , r.code , CONCAT( (SELECT p2.name FROM return_detail rd2 JOIN product p2 ON rd2.product_id = p2.id WHERE rd2.return_id = r.id ORDER BY rd2.id LIMIT 1), ' 외 ', (SELECT COUNT(*) - 1 FROM return_detail rd3 WHERE rd3.return_id = r.id) , '건' ) AS product_summary , r.status , r.created_at , r.total_amount , f.name AS franchise_name FROM `return` r JOIN franchise f ON r.franchise_id = f.id
r.franchise_id = #{franchiseId} AND #{franchiseId} IN
#{id}
r.franchise_id IN
#{id}
AND r.code LIKE CONCAT('%', #{code}, '%')
AND EXISTS ( SELECT 1 FROM return_detail rd JOIN product p ON rd.product_id = p.id WHERE rd.return_id = r.id AND p.name LIKE CONCAT('%', #{product}, '%') )
AND r.status LIKE CONCAT('%', #{status}, '%')
AND DATE(r.created_at) BETWEEN #{startDate} AND #{endDate}
ORDER BY r.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(DISTINCT r.id) FROM `return` r
r.franchise_id = #{franchiseId} AND #{franchiseId} IN
#{id}
r.franchise_id IN
#{id}
AND r.code LIKE CONCAT('%', #{code}, '%')
AND EXISTS ( SELECT 1 FROM return_detail rd JOIN product p ON rd.product_id = p.id WHERE rd.return_id = r.id AND p.name LIKE CONCAT('%', #{product}, '%') )
AND r.status LIKE CONCAT('%', #{status}, '%')
AND DATE(r.created_at) BETWEEN #{startDate} AND #{endDate}

SELECT id
FROM franchise
WHERE owner_id = #{userId}

SELECT -- 반품 상세 정보 rd.id AS returnDetailId , rd.status AS returnStatus , rd.return_type AS returnType , rd.quantity AS returnQuantity , rd.order_id AS orderId
-- 자재 정보 , p.id AS productId , p.code AS productCode , p.name AS productName , p.spec , p.purchase_unit AS purchaseUnit , p.unit , p.product_group_id AS productGroupId , p.product_type_id AS productTypeId , p.product_attribute_id AS productAttributeId , p.sale_price AS salePrice
FROM return_detail rd JOIN product p ON rd.product_id = p.id WHERE rd.return_id = #{returnId}
